const workflowRoot = '/Users/randy/Documents/code/agent-n8n';
const now = new Date();
const timestamp = now.toISOString().replace(/[-:TZ.]/g, '').slice(0, 14);
return [{
  json: {
    task: {
      id: `task-${timestamp}`,
      title: 'Add validation to create user endpoint',
      requirement: 'Reject invalid email input and return 400 with error message',
      acceptance_criteria: [
        'invalid email returns 400',
        'valid email still creates user',
        'existing tests continue to pass'
      ],
      file_hints: [
        'src/routes/users.ts',
        'tests/users.test.ts'
      ]
    },
    config: {
      repo_path: '/absolute/path/to/target-repo',
      default_branch: 'main',
      branch_prefix: 'agent/',
      workspace_lock_file: '.agent-run.lock',
      test_command: 'pnpm test',
      allowed_test_commands: ['pnpm test'],
      test_timeout_seconds: 300,
      max_repair_attempts: 2,
      max_changed_files: 5,
      max_diff_lines: 400,
      context_file_limit: 6,
      max_file_lines_for_context: 1000,
      edit_format: 'search_replace',
      fallback_edit_format: 'unified_diff',
      search_replace_context_lines: 3,
      prefer_targeted_tests_from_hints: false,
      allowed_failure_types: ['lint', 'type', 'unit_test', 'syntax', 'import']
    },
    run: {
      repair_attempts: 0,
      status: 'running'
    },
    workflow_root: workflowRoot,
    prompts: {
      plan: `${workflowRoot}/prompts/plan.md`,
      patch: `${workflowRoot}/prompts/patch.md`,
      repair: `${workflowRoot}/prompts/repair.md`,
      summary: `${workflowRoot}/prompts/summary.md`
    },
    scripts: {
      check_repo: `${workflowRoot}/scripts/check_repo.sh`,
      collect_context: `${workflowRoot}/scripts/collect_context.sh`,
      apply_patch: `${workflowRoot}/scripts/apply_patch.sh`,
      run_tests: `${workflowRoot}/scripts/run_tests.sh`,
      summarize_result: `${workflowRoot}/scripts/summarize_result.sh`,
      release_lock: `${workflowRoot}/scripts/release_lock.sh`
    }
  }
}];

const item = $input.first().json;
const payload = {
  repo_path: item.config.repo_path,
  default_branch: item.config.default_branch,
  branch_prefix: item.config.branch_prefix,
  workspace_lock_file: item.config.workspace_lock_file,
  task_id: item.task.id,
  test_command: item.config.test_command,
  allowed_test_commands: item.config.allowed_test_commands
};
const shellPayload = JSON.stringify(payload).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.check_repo} '${shellPayload}'` } }];

const item = $input.first().json;
const result = JSON.parse(item.stdout || '{}');
return [{ json: { ...item, precheck: result, run: { ...item.run, branch_name: result.branch_name || item.run.branch_name }, artifacts: { ...(item.artifacts || {}), check_repo_raw: result } } }];

const item = $input.first().json;
const payload = {
  repo_path: item.config.repo_path,
  file_hints: item.task.file_hints,
  context_file_limit: item.config.context_file_limit,
  max_file_lines_for_context: item.config.max_file_lines_for_context
};
const shellPayload = JSON.stringify(payload).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.collect_context} '${shellPayload}'` } }];

const item = $input.first().json;
const result = JSON.parse(item.stdout || '{}');
return [{ json: { ...item, context: result, artifacts: { ...(item.artifacts || {}), context_raw: result } } }];

const item = $input.first().json;
const fileBlock = JSON.stringify(item.context.selected_files || [], null, 2);
const skippedBlock = JSON.stringify(item.context.skipped_files || [], null, 2);
const prompt = `You are working inside one existing repository.

Task title:
${item.task.title}

Requirement:
${item.task.requirement}

Acceptance criteria:
${(item.task.acceptance_criteria || []).join('
')}

Repository summary:
${item.context.repo_summary || ''}

Relevant files:
${fileBlock}

Skipped files:
${skippedBlock}

Return JSON with:
- task_understanding
- target_files
- change_strategy
- risks
- should_stop
- stop_reason`;
return [{ json: { ...item, prompt, llm_stage: 'plan' } }];

const item = $input.first().json;
const body = item.body || item;
const text = body.output_text || body.choices?.[0]?.message?.content || body.content?.[0]?.text || '{}';
let plan;
try {
  plan = typeof text === 'string' ? JSON.parse(text) : text;
} catch (error) {
  plan = { should_stop: true, stop_reason: `plan parse failed: ${error.message}`, raw_text: text };
}
return [{ json: { ...item, plan } }];

const item = $input.first().json;
const body = item.body || item;
const text = body.output_text || body.choices?.[0]?.message?.content || body.content?.[0]?.text || '';
return [{ json: { ...item, artifacts: { ...(item.artifacts || {}), latest_edit_text: text }, edit_text: text } }];

const item = $input.first().json;
const payload = {
  repo_path: item.config.repo_path,
  edit_format: item.config.edit_format,
  edit_text: item.edit_text,
  search_replace_context_lines: item.config.search_replace_context_lines,
  max_changed_files: item.config.max_changed_files,
  max_diff_lines: item.config.max_diff_lines
};
const shellPayload = JSON.stringify(payload).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.apply_patch} '${shellPayload}'` } }];

const item = $input.first().json;
const apply = JSON.parse(item.stdout || '{}');
return [{ json: { ...item, apply } }];

const item = $input.first().json;
const payload = {
  repo_path: item.config.repo_path,
  test_command: item.config.test_command,
  allowed_test_commands: item.config.allowed_test_commands,
  test_timeout_seconds: item.config.test_timeout_seconds,
  prefer_targeted_tests_from_hints: item.config.prefer_targeted_tests_from_hints,
  file_hints: item.task.file_hints,
  allowed_failure_types: item.config.allowed_failure_types
};
const shellPayload = JSON.stringify(payload).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.run_tests} '${shellPayload}'` } }];

const item = $input.first().json;
const test = JSON.parse(item.stdout || '{}');
return [{ json: { ...item, test } }];

const item = $input.first().json;
const canRepair = Boolean(item.test.repairable) && Number(item.run.repair_attempts || 0) < Number(item.config.max_repair_attempts || 0);
return [{ json: { ...item, can_repair: canRepair } }];

const item = $input.first().json;
const prompt = `The previous code edit did not pass tests.

Acceptance criteria:
${(item.task.acceptance_criteria || []).join('
')}

Current changed files:
${JSON.stringify(item.apply.changed_files || [], null, 2)}

Test failure type:
${item.test.failure_type || ''}

Test failure excerpt:
${item.test.output_excerpt || ''}

Current diff:
${item.artifacts?.diff_excerpt || ''}

Rules:
- Return SEARCH/REPLACE blocks only
- Use the same exact block format as the initial patch prompt
- Fix only the observed failure
- Keep changes minimal
- Do not touch unrelated files
- Only use the latest failure excerpt provided here`;
return [{ json: { ...item, prompt, llm_stage: 'repair' } }];

const item = $input.first().json;
const body = item.body || item;
const text = body.output_text || body.choices?.[0]?.message?.content || body.content?.[0]?.text || '';
return [{ json: { ...item, edit_text: text, artifacts: { ...(item.artifacts || {}), latest_edit_text: text } } }];

const item = $input.first().json;
const payload = { repo_path: item.config.repo_path };
if (item.precheck?.lock_file) {
  payload.lock_file = item.precheck.lock_file;
}
const shellPayload = JSON.stringify(payload).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.summarize_result} '${shellPayload}'` } }];

const item = $input.first().json;
const summary = JSON.parse(item.stdout || '{}');
const status = item.test?.passed ? 'success' : (item.plan?.should_stop || item.precheck?.ok === false || item.apply?.applied === false ? 'stopped' : 'failed');
return [{ json: { ...item, summary, final: { status, summary: item.plan?.task_understanding || item.task.title, changed_files: summary.changed_files || [], repair_attempts: item.run.repair_attempts || 0, test_result: item.test || null, stop_reason: item.plan?.stop_reason || item.precheck?.stop_reason || item.apply?.stop_reason || item.test?.output_excerpt || '' } } }];

const item = $input.first().json;
const shellPayload = JSON.stringify({ lock_file: item.precheck?.lock_file || '' }).replace(/'/g, `'\\''`);
return [{ json: { ...item, command: `${item.scripts.release_lock} '${shellPayload}'` } }];

const item = $input.first().json;
const final = {
  status: 'stopped',
  summary: item.task?.title || 'precheck stopped',
  changed_files: [],
  repair_attempts: item.run?.repair_attempts || 0,
  test_result: null,
  stop_reason: item.precheck?.stop_reason || item.plan?.stop_reason || item.apply?.stop_reason || 'workflow stopped before tests'
};
return [{ json: { ...item, final } }];
